@dataclass
class Record:
    index: int
    hash: int
    size: int
    offset: int
    extra: int
    head: bytes = b""

@dataclass
class Archive:
    path: Path
    size: int
    count: int
    mode64: bool
    table_start: int
    rec_size: int
    records: List[Record]

# --------------------------------------------------------------------------------------
# Basic helpers
# --------------------------------------------------------------------------------------

def pause_exit(code=0):
    try:
        input("\nPress Enter to close...")
    except Exception:
        pass
    return code

def visible_escape(s: str) -> str:
    return s.replace('\\', '\\\\').replace('\r','\\r').replace('\n','\\n').replace('\t','\\t')

def visible_unescape(s: str) -> str:
    out=[]; i=0
    while i < len(s):
        ch=s[i]
        if ch=='\\' and i+1 < len(s):
            n=s[i+1]
            if n=='n': out.append('\n'); i+=2; continue
            if n=='r': out.append('\r'); i+=2; continue
            if n=='t': out.append('\t'); i+=2; continue
            if n=='\\': out.append('\\'); i+=2; continue
        out.append(ch); i+=1
    return ''.join(out)

def clean_key(s: str) -> str:
    return s.replace('\r\n','\n').replace('\r','\n').strip()

def lookup_translation(text: str, translations: Dict[str,str]) -> str:
    """Translation lookup with tolerance for literal backslash-n vs real newline."""
    candidates=[]
    t=clean_key(text)
    candidates.append(t)
    candidates.append(t.replace('\\n','\n'))
    candidates.append(t.replace('\n','\\n'))
    candidates.append(re.sub(r'\s+', ' ', t))
    if '\\n' in t:
        candidates.append(re.sub(r'\s+', ' ', t.replace('\\n',' ')))
    if '\n' in t:
        candidates.append(re.sub(r'\s+', ' ', t.replace('\n',' ')))
    seen=set()
    for c in candidates:
        if c in seen: continue
        seen.add(c)
        if c in translations:
            return translations[c]
    return text

def parse_translation_txt(path: Path) -> Dict[str,str]:
    translations: Dict[str,str] = OrderedDict()
    current=None
    with path.open('r', encoding='utf-8-sig', errors='replace') as f:
        for raw in f:
            line=raw.rstrip('\r\n')
            if line.startswith('ORIGINAL: '):
                current=visible_unescape(line[len('ORIGINAL: '):])
            elif line.startswith('TRANSLATION:') and current is not None:
                rest=line[len('TRANSLATION:'):]
                if rest.startswith(' '): rest=rest[1:]
                translations[clean_key(current)] = visible_unescape(rest)
                current=None
    return translations

def add_export_pair(pairs: OrderedDict, original: str):
    original=clean_key(original)
    if not original: return
    # Very conservative asset-id filter
    if re.fullmatch(r'[A-Z0-9_]{3,32}', original) and not any(ch in original for ch in ' .,:;!?-'):
        return
    pairs.setdefault(original, original)

def write_export_txt(path: Path, pairs: OrderedDict):
    with path.open('w', encoding='utf-8', newline='\n') as f:
        for orig, trans in pairs.items():
            f.write('ORIGINAL: ' + visible_escape(orig) + '\n')
            f.write('TRANSLATION: ' + visible_escape(trans) + '\n\n')

def parse_archive(path: Path) -> Archive:
    size=path.stat().st_size
    with path.open('rb') as f:
        head=f.read(4)
        if len(head)<4: raise RuntimeError(f'{path.name}: túl rövid fájl')
        count, unk = struct.unpack('<HH', head)
        if count <= 0 or count > 200000:
            raise RuntimeError(f'{path.name}: érvénytelen file_count: {count}')
        hash_off=4
        table_start=hash_off + count*4
        f.seek(hash_off)
        hashes=list(struct.unpack('<'+'I'*count, f.read(count*4)))
        # Defiance Remastered DAT-oknál 64 bites rekordok vannak. Fallback 32 bithez.
        remain=size-table_start
        if remain >= count*24:
            rec_size=24; mode64=True
            fmt='<QQQ'
        elif remain >= count*12:
            rec_size=12; mode64=False
            fmt='<III'
        else:
            raise RuntimeError(f'{path.name}: nincs elég hely rekordtáblához')
        records=[]
        f.seek(table_start)
        for i,h in enumerate(hashes):
            raw=f.read(rec_size)
            vals=struct.unpack(fmt, raw)
            if mode64:
                sz, off, extra = vals
            else:
                sz, off, extra = vals
            records.append(Record(i,h,int(sz),int(off),int(extra)))
        # read small heads
        for r in records:
            if r.size and 0 <= r.offset < size:
                try:
                    f.seek(r.offset); r.head=f.read(min(32,r.size))
                except Exception:
                    r.head=b''
    return Archive(path,size,count,mode64,table_start,rec_size,records)

def read_record(f, rec: Record, arch_size: int) -> bytes:
    if rec.offset < 0 or rec.offset + rec.size > arch_size:
        return b''
    f.seek(rec.offset)
    return f.read(rec.size)

def record_entry_offset(arch: Archive, rec: Record) -> int:
    return arch.table_start + rec.index * arch.rec_size

def align_file(f, align=ALIGN) -> int:
    f.seek(0, os.SEEK_END)
    pos=f.tell()
    pad=(-pos) % align
    if pad:
        f.write(b'\x00'*pad); pos+=pad
    return pos


def write_record_in_place(arch: Archive, rec: Record, data: bytes):
    """Overwrite an existing record at its current offset.

    Used only for CR/binary cinematic records where the new bytes MUST have
    exactly the same length as the original record. This avoids changing the
    record table offset/size and avoids moving binary scene data.
    """
    if len(data) != rec.size:
        raise RuntimeError(f'in-place patch mérethiba rec={rec.index}: {len(data)} != {rec.size}')
    with arch.path.open('r+b') as f:
        f.seek(rec.offset)
        f.write(data)
    print(f'  INPLACE {arch.path.name} rec={rec.index} hash=0x{rec.hash:08X} size változatlan {rec.size}')

def append_and_update(arch: Archive, rec: Record, data: bytes):
    with arch.path.open('r+b') as f:
        new_off=align_file(f)
        f.write(data)
        f.seek(record_entry_offset(arch, rec))
        if arch.mode64:
            f.write(struct.pack('<QQQ', len(data), new_off, rec.extra))
        else:
            f.write(struct.pack('<III', len(data), new_off, rec.extra))
    print(f'  PATCH {arch.path.name} rec={rec.index} hash=0x{rec.hash:08X} size {rec.size}->{len(data)} off 0x{rec.offset:X}->0x{new_off:X}')

def append_once_update_many(arch: Archive, records: List[Record], data: bytes, label: str = 'PATCH-GROUP'):
    """Append data once, then point all duplicate table records to the same new blob.

    Some Defiance TextEntry records are duplicated in the table and originally point
    to the very same offset/size. Appending one patched copy per duplicate works,
    but wastes space and creates unnecessary changed records. This keeps the
    record table semantically equivalent while avoiding repeated appended copies.
    """
    if not records:
        return
    with arch.path.open('r+b') as f:
        new_off=align_file(f)
        f.write(data)
        for rec in records:
            f.seek(record_entry_offset(arch, rec))
            if arch.mode64:
                f.write(struct.pack('<QQQ', len(data), new_off, rec.extra))
            else:
                f.write(struct.pack('<III', len(data), new_off, rec.extra))
            rec.offset = new_off
            rec.size = len(data)
    idxs = ','.join(str(r.index) for r in records[:8])
    if len(records) > 8:
        idxs += ',...'
    print(f'  {label} {arch.path.name} recs={idxs} hash=0x{records[0].hash:08X} copies={len(records)} size->{len(data)} off=0x{new_off:X}')

# --------------------------------------------------------------------------------------
# locals.bin
# --------------------------------------------------------------------------------------

def parse_locals(data: bytes) -> Optional[Tuple[int,int,List[int],List[str]]]:
    if len(data)<8: return None
    lang_id, count=struct.unpack_from('<II', data, 0)
    if count <= 0 or count > 100000: return None
    table_end=8+count*4
    if table_end > len(data): return None
    offsets=list(struct.unpack_from('<'+'I'*count, data, 8))
    strings=[]
    for off in offsets:
        if off==0:
            strings.append(''); continue
        if off<0 or off>=len(data): return None
        end=data.find(b'\x00', off)
        if end<0: return None
        try:
            strings.append(data[off:end].decode('utf-8'))
        except UnicodeDecodeError:
            return None
    return lang_id,count,offsets,strings

