def is_protected_locals_slot(idx:int, s:str) -> bool:
    for a,b in PROTECTED_LOCALS_SLOT_RANGES:
        if a <= idx <= b:
            return True
    return False

def build_locals(lang_id:int, count:int, old_strings:List[str], translations:Dict[str,str]) -> bytes:
    out=bytearray()
    out.extend(struct.pack('<II', lang_id, count))
    out.extend(b'\x00'*(count*4))
    offsets=[]
    protected_count=0
    for idx,s in enumerate(old_strings):
        if not s:
            offsets.append(0); continue
        if is_protected_locals_slot(idx, s):
            ns=PROTECTED_LOCALS_ORIGINALS.get(idx, s)
            protected_count += 1
        else:
            ns=translate_timed_plain(s, translations)
        offsets.append(len(out))
        out.extend(ns.encode('utf-8')+b'\x00')
    for i,off in enumerate(offsets):
        struct.pack_into('<I', out, 8+i*4, off)
    if protected_count:
        print(f'  locals.bin: vedett zene/asset slotok valtozatlanul hagyva: {protected_count}')
    return bytes(out)

TIMING_LINE_RE=re.compile(r'^\s*\d+\s+0\s*$')

def translate_timed_plain(s: str, translations:Dict[str,str]) -> str:
    # Handles locals strings where timing markers are separate lines like "78 0".
    norm=s.replace('\r\n','\n').replace('\r','\n')
    lines=norm.split('\n')
    out=[]; buf=[]; saw=False
    def flush():
        nonlocal buf
        if not buf: return
        chunk='\n'.join(buf)
        key=clean_key(chunk)
        if key:
            tr=lookup_translation(key, translations)
            out.append(tr)
        else:
            out.append(chunk)
        buf=[]
    for line in lines:
        if TIMING_LINE_RE.match(line):
            saw=True; flush(); out.append(line)
        else:
            buf.append(line)
    flush()
    if saw:
        return '\n'.join(out)
    return lookup_translation(s, translations)

def find_english_locals(arch:Archive) -> Optional[Tuple[Record,bytes,Tuple[int,int,List[int],List[str]]]]:
    with arch.path.open('rb') as f:
        # known hash first
        for rec in arch.records:
            if rec.hash == PCE_ENGLISH_LOCALS_HASH:
                data=read_record(f,rec,arch.size); parsed=parse_locals(data)
                if parsed and parsed[0]==0: return rec,data,parsed
        # fallback by structure
        for rec in arch.records:
            if rec.size > 2_000_000 or rec.size < 1000: continue
            data=read_record(f,rec,arch.size); parsed=parse_locals(data)
            if parsed and parsed[0]==0 and parsed[1] >= 4000:
                return rec,data,parsed
    return None

# --------------------------------------------------------------------------------------
# Version 1 / TextEntry records
# --------------------------------------------------------------------------------------

LANG_LINE_RE=re.compile(r'(lang_english\s+[^\r\n]*?\s+")(.*?)("\s*(?:\r\n|\n|\r|$))', re.S)
SEG_RE=re.compile(r'\\\(([^)]*)\)')

def split_textentry_english_segments(body: str) -> List[str]:
    matches=list(SEG_RE.finditer(body))
    if not matches:
        return [body.strip()] if body.strip() else []
    segs=[]
    for i,m in enumerate(matches):
        start=m.end(); end=matches[i+1].start() if i+1<len(matches) else len(body)
        txt=body[start:end].strip()
        if txt: segs.append(txt)
    return segs

def rebuild_textentry_english_body(body: str, translations:Dict[str,str]) -> Tuple[str,int]:
    matches=list(SEG_RE.finditer(body))
    if not matches:
        tr=lookup_translation(body, translations)
        return tr.replace('\n','\\n').replace('\r',''), int(tr!=body)
    out=[]; changed=0
    for i,m in enumerate(matches):
        out.append(m.group(0))
        start=m.end(); end=matches[i+1].start() if i+1<len(matches) else len(body)
        seg=body[start:end]
        # Preserve leading/trailing spaces around segment.
        lead=re.match(r'^\s*',seg).group(0)
        trail=re.search(r'\s*$',seg).group(0)
        core=seg[len(lead):len(seg)-len(trail) if trail else len(seg)]
        if core.strip():
            tr=lookup_translation(core, translations)
            # TextEntry stores line breaks as literal \n, not real CR/LF.
            tr=tr.replace('\r','').replace('\n','\\n')
            if tr != core: changed += 1
            out.append(lead+tr+trail)
        else:
            out.append(seg)
    return ''.join(out), changed

def _split_text_blob_and_suffix(data: bytes) -> Optional[Tuple[str, bytes, bool]]:
    """TextEntry records may be either NUL-terminated text+binary suffix or pure text without NUL.
    v5.6 skipped pure TextEntry records, which is why the prologue/opening stayed English.
    Returns (text_blob, suffix, had_nul).
    """
    nul = data.find(b'\x00')
    if nul >= 0:
        blob_bytes = data[:nul]
        suffix = data[nul+1:]
        had_nul = True
    else:
        blob_bytes = data
        suffix = b''
        had_nul = False
    try:
        blob = blob_bytes.decode('utf-8')
    except UnicodeDecodeError:
        return None
    return blob, suffix, had_nul

def patch_textentry_record(data: bytes, translations:Dict[str,str]) -> Tuple[bytes,int]:
    # Replace TextEntry records whether they are NUL-terminated or pure text.
    split = _split_text_blob_and_suffix(data)
    if not split:
        return data,0
    blob, suffix, had_nul = split
    if 'TextEntry' not in blob or 'lang_english' not in blob:
        return data,0
    total=0
    def repl(m):
        nonlocal total
        newbody,cnt=rebuild_textentry_english_body(m.group(2), translations)
        total += cnt
        return m.group(1)+newbody+m.group(3)
    newblob=LANG_LINE_RE.sub(repl, blob)
    if total <= 0 or newblob == blob:
        return data,0
    if had_nul:
        newdata=newblob.encode('utf-8') + b'\x00' + suffix
    else:
        newdata=newblob.encode('utf-8')
    return newdata,total

def export_textentry_record(data:bytes, pairs:OrderedDict):
    split = _split_text_blob_and_suffix(data)
    if not split:
        return
    blob, suffix, had_nul = split
    if 'TextEntry' not in blob or 'lang_english' not in blob: return
    for m in LANG_LINE_RE.finditer(blob):
        for seg in split_textentry_english_segments(m.group(2)):
            add_export_pair(pairs, seg.replace('\\n','\n'))

# --------------------------------------------------------------------------------------
# CR-delimited language blocks: 7\rChinese\r0\rEnglish\r1\rFrench...\r\0
# --------------------------------------------------------------------------------------

def parse_cr_block_at(data:bytes, start:int):
    n=len(data); p=start; entries=[]
    while p+2 <= n and p < n and 48 <= data[p] <= 57 and p+1 < n and data[p+1] == 0x0D:
        lang=data[p]-48
        text_start=p+2
        end=data.find(b'\x0D', text_start)
        if end < 0: return None
        raw=data[text_start:end]
        try:
            text=raw.decode('utf-8')
        except UnicodeDecodeError:
            return None
        if not text or len(text) > 1000:
            return None
        entries.append((lang, text_start, end, text))
        p=end+1
        if p < n and data[p] == 0x00:
            block_end=p+1
            break
    else:
        return None
    if len(entries) < 3 or not any(e[0]==0 for e in entries):
        return None
    langs={e[0] for e in entries}
    if len(langs) < 3:
        return None
    return start, block_end, entries

def find_cr_blocks(data:bytes) -> List[Tuple[int,int,List[Tuple[int,int,int,str]]]]:
    blocks=[]; i=0; n=len(data)
    while i < n-4:
        if 48 <= data[i] <= 57 and data[i+1] == 0x0D:
            res=parse_cr_block_at(data,i)
            if res:
                # Filter out random binary false positives: require English entry with letters/spaces.
                en=[e[3] for e in res[2] if e[0]==0]
                if en and re.search(r'[A-Za-z]{2,}', en[0]):
                    blocks.append(res)
                    i=res[1]
                    continue
        i += 1
    return blocks

def _pad_utf8_to_len(text: str, target_len: int) -> Optional[bytes]:
    raw = text.encode('utf-8')
    if len(raw) > target_len:
        return None
    return raw + (b' ' * (target_len - len(raw)))

def patch_cr_block_slot_safe(data: bytes, start: int, end: int, entries, translations: Dict[str,str]) -> Tuple[bytes,int]:
    """Patch one CR-delimited language block without changing its byte length.

    v6.2 HYBRID stratégia:
      1) Elsőként a v5.9-ben már stabilnak bizonyult módszert használja:
         - ha a magyar befér az eredeti 0-s angol slotba, oda írja;
         - ha nem fér be, keres egy nagyobb meglévő donor nyelvi slotot;
         - a donor slot nyelvkódja 0 lesz, a régi angol slot megkapja a donor kódját.
         Ez megőrzi a blokk szerkezetét és a lehető legkisebb módosítás.

      2) Csak ha nincs elég nagy donor slot, akkor lép életbe a compact fallback:
         - a teljes meglévő CR blokk byte-terét használja újra;
         - a blokk mérete változatlan marad;
         - a rekord offsetje/mérete nem változik;
         - a bináris adat a blokk után nem csúszik el.

    Így a v5.9 stabilitása marad az alap, de a hosszabb magyar soroknál
    (pl. "to shatter these barriers.") már van esély karakterlimit nélkül is.
    """
    en_entries=[e for e in entries if e[0]==0]
    if not en_entries:
        return data,0
    lang, ts, te, old_text = en_entries[0]
    tr = lookup_translation(old_text, translations).replace('\r',' ').replace('\n','\\n')
    if tr == old_text:
        return data,0
    tr_raw = tr.encode('utf-8')

    out = bytearray(data)
    en_cap = te - ts

    # 1) Minimális, eredeti angol sloton belüli patch.
    raw = _pad_utf8_to_len(tr, en_cap)
    if raw is not None:
        out[ts:te] = raw
        return bytes(out),1

    # 2) v5.9 stabil donor-slot csere.
    donors = sorted([e for e in entries if e[0] != 0], key=lambda e: (e[2]-e[1]), reverse=True)
    donor = None
    for e in donors:
        if (e[2]-e[1]) >= len(tr_raw):
            donor = e
            break
    if donor is not None:
        d_lang, d_ts, d_te, d_text = donor
        d_cap = d_te - d_ts
        # Nyelvkódok cseréje. Az entry text előtt közvetlenül: ASCII digit + CR.
        out[ts-2:ts-1] = str(d_lang).encode('ascii')
        out[d_ts-2:d_ts-1] = b'0'
        out[d_ts:d_te] = _pad_utf8_to_len(tr, d_cap)
        out[ts:te] = _pad_utf8_to_len(old_text, en_cap)
        return bytes(out),1

    # 3) Compact fallback: teljes blokk újrahasznosítása azonos byte-hosszal.
    # Megpróbálunk néhány nyelvi entryt megtartani, de a 0-s magyar az elsődleges.
    block_len = end - start
    prefix = b'0\r' + tr_raw + b'\r'
    suffix = b'\r\x00'
    if len(prefix) + len(suffix) > block_len:
        # Még a teljes blokk sem elég, ekkor biztonságból nem módosítunk.
        return data,0

    # A megmaradó helyre rövid, jól formált dummy entry kerül. Ez nem növeli a blokkot.
    # A játék angol módban a 0-s entryt veszi fel; a többi nyelv itt nem cél.
    rest_len = block_len - len(prefix) - len(suffix)
    if rest_len >= 4:
        filler = b'1\r' + (b' ' * (rest_len - 3)) + b'\r'
    else:
        filler = b' ' * rest_len
    new_block = prefix + filler + suffix
    if len(new_block) != block_len:
        return data,0
    out[start:end] = new_block
    return bytes(out),1

def patch_cr_blocks(data:bytes, translations:Dict[str,str]) -> Tuple[bytes,int]:
    blocks=find_cr_blocks(data)
    if not blocks:
        # Some CR-coded subtitles are embedded in a way that our full block parser
        # intentionally rejects. Still patch safe same-size/shorter English lang0
        # entries like: 0\rEnglish text\r .
        return patch_loose_lang0_entries(data, translations)
    out=data; changed=0
    # Patch from the end backwards only as a safety habit. Length never changes.
    for start,end,entries in reversed(blocks):
        newout,c=patch_cr_block_slot_safe(out,start,end,entries,translations)
        if c:
            out=newout; changed += c
    # Fallback pass for missed lang0 entries inside unusual binary containers.
    newout,c2=patch_loose_lang0_entries(out, translations)
    if c2:
        out=newout; changed += c2
    return out, changed

def patch_loose_lang0_entries(data: bytes, translations: Dict[str,str]) -> Tuple[bytes,int]:
    """Safely patch loose 0\rEnglish\r entries without changing record length.

    This is a conservative fallback for cases where a real in-game subtitle uses
    the CR language code format but the surrounding block is not recognized as a
    complete multilingual block by the stricter parser. It only patches lang=0
    entries when the translated UTF-8 text fits into the original byte range.
    Longer text is left for the full compact-block path.
    """
    out=bytearray(data)
    changed=0
    pos=0
    n=len(out)
    while True:
        pos=out.find(b'0\r', pos)
        if pos < 0 or pos+2 >= n:
            break
        ts=pos+2
        te=out.find(b'\r', ts)
        if te < 0:
            break
        raw=bytes(out[ts:te])
        if 0 < len(raw) <= 1000:
            try:
                old=raw.decode('utf-8')
            except UnicodeDecodeError:
                old=None
            if old and re.search(r'[A-Za-z]{2,}', old):
                tr=lookup_translation(old, translations).replace('\r',' ').replace('\n','\\n')
                if tr != old:
                    tb=tr.encode('utf-8')
                    if len(tb) <= len(raw):
                        out[ts:te] = tb + (b' ' * (len(raw)-len(tb)))
                        changed += 1
        pos=te+1
    return bytes(out),changed

def export_cr_blocks(data:bytes, pairs:OrderedDict):
    for start,end,entries in find_cr_blocks(data):
        for lang,ts,te,text in entries:
            if lang == 0:
                add_export_pair(pairs, text)

# --------------------------------------------------------------------------------------
# Export/import operations
# --------------------------------------------------------------------------------------

def export_from_archives(base:Path, x64:Optional[Archive], hd:Optional[Archive]):
    pairs=OrderedDict()
    if x64:
        print('[EXPORT] bigfile.x64.dat')
        with x64.path.open('rb') as f:
            loc=find_english_locals(x64)
            if loc:
                rec,data,parsed=loc
                print(f'  locals.bin rec={rec.index} strings={sum(1 for s in parsed[3] if s)}')
                skipped_protected=0
                for idx,s in enumerate(parsed[3]):
                    if s and is_protected_locals_slot(idx, s):
                        skipped_protected += 1
                        continue
                    for part in export_parts_from_plain(s):
                        add_export_pair(pairs, part)
                if skipped_protected:
                    print(f'  locals.bin: exportbol kihagyott vedett zene/asset slotok: {skipped_protected}')
            # TextEntry records
            te_count=0
            for rec in x64.records:
                if rec.head.startswith(b'Version 1') and rec.size < 2_000_000:
                    data=read_record(f,rec,x64.size)
                    before=len(pairs); export_textentry_record(data,pairs)
                    if len(pairs)>before: te_count += 1
            print(f'  TextEntry rekordok exportálva: {te_count}')
            # CR known records
            cr_count=0
            for rec in x64.records:
                if rec.hash in KNOWN_X64_MULTILANG_HASHES and 0 < rec.size <= MAX_KNOWN_RECORD_SIZE:
                    data=read_record(f,rec,x64.size)
                    before=len(pairs); export_cr_blocks(data,pairs)
                    if len(pairs)>before: cr_count += 1
            print(f'  CR nyelvkódos rekordok exportálva: {cr_count}')
    # bigfilehd deliberately not patched in this v5.6 unless future exact structure is needed.
    out=base/TXT_NAME
    write_export_txt(out,pairs)
    print(f'[OK] Export kész: {out.name}, párok: {len(pairs)}')

def export_parts_from_plain(s:str) -> List[str]:
    if not s: return []
    norm=s.replace('\r\n','\n').replace('\r','\n')
    lines=norm.split('\n')
    parts=[]; buf=[]; saw=False
    def flush():
        nonlocal buf
        txt='\n'.join(buf).strip()
        if txt: parts.append(txt)
        buf=[]
    for line in lines:
        if TIMING_LINE_RE.match(line):
            saw=True; flush()
        else:
            buf.append(line)
    flush()
    return parts if saw else [s.strip()]

def is_cr_candidate_record(rec: Record) -> bool:
    if not (0 < rec.size <= MAX_KNOWN_RECORD_SIZE):
        return False
    if rec.hash in KNOWN_X64_MULTILANG_HASHES:
        return True
    # Many scene/cinematic binary records have a small header like xx 56 00 00.
    # Scan these too, because a few subtitle blocks were found outside the old hash list.
    h=rec.head or b''
    return len(h) >= 4 and h[1:4] == b'V\x00\x00'

def import_to_archives(base:Path, x64:Optional[Archive], hd:Optional[Archive]):
    txt=base/TXT_NAME
    translations=parse_translation_txt(txt)
    ui_progress(5, 'Reading translation file')
    total_records=0
    if x64:
        ui_progress(10, 'Preparing bigfile.x64.dat')
        _pre_file_size = x64.path.stat().st_size
        _pre_cr_layout = {rec.index: (rec.hash, rec.offset, rec.size) for rec in x64.records if rec.hash in KNOWN_X64_MULTILANG_HASHES}
        # 1) locals.bin
        loc=find_english_locals(x64)
        if loc:
            rec,data,parsed=loc
            newdata=build_locals(parsed[0], parsed[1], parsed[3], translations)
            if newdata != data:
                ui_progress(20, 'Updating main text table')
                append_and_update(x64,rec,newdata); total_records+=1
            else:
                ui_progress(20, 'Main text table already up to date')
        # 2) TextEntry records
        # Duplicate TextEntry records often point to the same original blob.
        # Patch each unique (hash, offset, size) blob once and update all duplicate
        # table entries to the same appended patched copy. This greatly reduces
        # unnecessary file growth compared with one append per duplicate.
        textentry_groups = OrderedDict()
        for rec in x64.records:
            if rec.head.startswith(b'Version 1') and rec.size < 2_000_000:
                textentry_groups.setdefault((rec.hash, rec.offset, rec.size), []).append(rec)
        ui_progress(35, 'Updating cinematic text records')
        with x64.path.open('rb') as f:
            changed_textentry_groups=0
            changed_textentry_records=0
            for key, group in textentry_groups.items():
                rec0 = group[0]
                data=read_record(f,rec0,x64.size)
                newdata,cnt=patch_textentry_record(data, translations)
                if cnt and newdata != data:
                    append_once_update_many(x64, group, newdata, 'PATCH TextEntry')
                    changed_textentry_groups += 1
                    changed_textentry_records += len(group)
                    total_records += len(group)
        # Need reparse x64 after appends? Not necessary for remaining original records; table changes do not affect offsets of others.
        ui_progress(55, 'Updating binary subtitle records')
        cr_candidates=[rec for rec in x64.records if is_cr_candidate_record(rec)]
        with x64.path.open('rb') as f:
            changed_cr=0
            total_cr=max(1,len(cr_candidates))
            for i,rec in enumerate(cr_candidates):
                if i % 50 == 0:
                    ui_progress(55 + (35*i)//total_cr, 'Updating binary subtitle records')
                data=read_record(f,rec,x64.size)
                newdata,cnt=patch_cr_blocks(data, translations)
                if cnt and newdata != data:
                    if len(newdata) != len(data):
                        continue
                    # CR/binary cinematic record: never append and never resize.
                    write_record_in_place(x64,rec,newdata)
                    changed_cr += 1; total_records+=1
        # Built-in safety check: CR/binary rekordoknak TILOS offsetet vagy size-t váltani.
        _bad = []
        for rec in x64.records:
            old_layout = _pre_cr_layout.get(rec.index)
            if old_layout and old_layout != (rec.hash, rec.offset, rec.size):
                _bad.append((rec.index, rec.hash, old_layout[1], old_layout[2], rec.offset, rec.size))
        if _bad:
            raise RuntimeError('Safety check failed: a CR/binary record changed offset or size.')
        _post_file_size = x64.path.stat().st_size
        _delta = _post_file_size - _pre_file_size
        if _delta > 250_000_000:
            raise RuntimeError('Safety check failed: unexpected large DAT size increase. Please restore clean DAT files and try again.')
        ui_progress(95, 'Final safety checks')
    if hd:
        pass
    ui_progress_done('Translation installed successfully')

def find_archives(base:Path) -> Tuple[Optional[Archive],Optional[Archive]]:
    x64p=base/'bigfile.x64.dat'; hdp=base/'bigfilehd.dat'
    x64=parse_archive(x64p) if x64p.exists() else None
    hd=parse_archive(hdp) if hdp.exists() else None
    if x64: print(f'[OK] bigfile.x64.dat: records={x64.count}, mode={"64-bit" if x64.mode64 else "32-bit"}')
    if hd: print(f'[OK] bigfilehd.dat: records={hd.count}, mode={"64-bit" if hd.mode64 else "32-bit"}')
    return x64,hd

def main():
    base=Path(__file__).resolve().parent
    mode = 'Install' if (base/TXT_NAME).exists() else 'Export'
    ui_header(mode)
    ui_progress(0, 'Checking files')
    x64,hd=find_archives(base)
    if not x64 and not hd:
        raise RuntimeError('Could not find bigfile.x64.dat or bigfilehd.dat next to this installer.')
    if (base/TXT_NAME).exists():
        import_to_archives(base,x64,hd)
    else:
        ui_progress(10, 'Exporting translation template')
        # Temporarily enable minimal internal output for export only if needed; template creation is mostly for you.
        export_from_archives(base,x64,hd)
        ui_progress_done('Translation template exported')
    return 0

if __name__ == '__main__':
    try:
        code=main()
    except Exception as exc:
        _builtins.print('\n\nInstallation failed.')
        _builtins.print(str(exc))
        code=1
    raise SystemExit(pause_exit(code))
